command:example.dev:code:
$secret = Read-Host 'Client Secret' -AsSecureString $creds = @{ ClientId = $env:MC_CLIENT_ID; ClientSecret = $secret }
# Step 1: find the delegate record ID $delegate = Get-MimecastDelegateUsers -PrimaryAddress 'shared@contoso.com' @creds | Where-Object EmailAddress -eq 'alice@contoso.com'
# Step 2: remove it Remove-MimecastDelegateUser -PrimaryAddress 'shared@contoso.com' ` -DelegateId $delegate.DelegateId @creds
